void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

void show_progress_done(void) { flushed_printf("\n"); }

template <typename T>
struct DevOps {
  __device__ static inline T add(T a, T b) { return a + b; }
  __device__ static inline T mul(T a, T b) { return a * b; }
  __device__ static inline T zero() { return (T)0; }
  __device__ static inline T minus_one() { return (T)-1; }
  __device__ static inline bool is_equal(T a, T b) { return a == b; }
};

template <>
struct DevOps<__half2> {
  __device__ static inline __half2 add(__half2 a, __half2 b) { return __hadd2(a, b); }
  __device__ static inline __half2 mul(__half2 a, __half2 b) { return __hmul2(a, b); }
  __device__ static inline __half2 zero() { return __float2half2_rn(0.0f); }
  __device__ static inline __half2 minus_one() { return __float2half2_rn(-1.0f); }
  __device__ static inline bool is_equal(__half2 a, __half2 b) {
    return __heq(__low2half(a), __low2half(b)) && __heq(__high2half(a), __high2half(b));
  }
};

template <typename T, bool BLOCK_STRIDED>
__global__ void benchmark_func_cuda(T seed,
                                    T* g_data,
                                    int compute_iters,
                                    int elements_per_thread,
                                    int fusion_degree) {
  const unsigned int blockSize = blockDim.x;
  const int tid = (int)threadIdx.x;
  const int gid = (int)(blockIdx.x * blockDim.x + threadIdx.x);

  int stride, idx;
  if (BLOCK_STRIDED) {
    stride = (int)blockSize;
    idx = (int)(blockIdx.x * blockSize * elements_per_thread + tid);
  } else {
    const int grid_size = (int)(blockSize * gridDim.x);
    stride = grid_size;
    idx = gid;
  }
  const int big_stride = (int)(gridDim.x * blockSize * elements_per_thread);

  constexpr int MAX_EPT = 64;
  if (elements_per_thread > MAX_EPT) return;
  T tmps[MAX_EPT];

  for (int k = 0; k < fusion_degree; k++) {
#pragma unroll
    for (int j = 0; j < elements_per_thread; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
      for (int i = 0; i < compute_iters; i++) {
        tmps[j] = DevOps<T>::add(DevOps<T>::mul(tmps[j], tmps[j]), seed);
      }
    }

    T sum = DevOps<T>::zero();
#pragma unroll
    for (int j = 0; j < elements_per_thread; j += 2) {
      sum = DevOps<T>::add(sum, DevOps<T>::mul(tmps[j], tmps[j + 1]));
    }

    if (DevOps<T>::is_equal(sum, DevOps<T>::minus_one())) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}

template <typename T>
double launch_timed_kernel(void* d_buffer,
                           T seed,
                           long total_threads,
                           size_t workgroupsize,
                           int compute_iters,
                           int elements_per_thread,
                           int fusion_degree,
                           bool block_strided,
                           bool use_os_timer) {
  const long num_blocks = total_threads / (long)workgroupsize;
  dim3 block((unsigned int)workgroupsize);
  dim3 grid((unsigned int)num_blocks);

  cudaEvent_t ev_start, ev_stop;
  if (!use_os_timer) {
    CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
    CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
    CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
  }

  auto ts_start = getTimestamp();

  if (block_strided) {
    benchmark_func_cuda<T, true><<<grid, block>>>(
        seed, reinterpret_cast<T*>(d_buffer), compute_iters, elements_per_thread, fusion_degree);
  } else {
    benchmark_func_cuda<T, false><<<grid, block>>>(
        seed, reinterpret_cast<T*>(d_buffer), compute_iters, elements_per_thread, fusion_degree);
  }
  CUDA_SAFE_CALL(cudaGetLastError());

  double duration_ms = 0.0;
  if (use_os_timer) {
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
    duration_ms = getElapsedtime(ts_start);
  } else {
    CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
    CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
    float ms = 0.0f;
    CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
    duration_ms = (double)ms;
    CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
  }

  return duration_ms;
}

void runbench_warmup(void* d_buffer, long size, size_t workgroupsize, bool block_strided) {
  const long reduced_grid_size = size / 256;
  const int16_t seed = 1;
  (void)launch_timed_kernel<int16_t>(d_buffer, seed, reduced_grid_size, workgroupsize, 0, 1, 1,
                                     block_strided, false);
}

void runbench(const int compute_iterations[],
              unsigned int krn_idx,
              void* d_buffer,
              long size,
              size_t workgroupsize,
              unsigned int elements_per_wi,
              unsigned int fusion_degree,
              bool block_strided,
              bool use_os_timer,
              bool enable_dp,
              bool enable_hp) {
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const int current_compute_iterations = compute_iterations[krn_idx];
  const long long computations =
      (elements_per_wi * (long long)compute_grid_size +
       (2 * elements_per_wi * current_compute_iterations) * (long long)compute_grid_size) *
      fusion_degree;
  const long long memoryoperations = size;

  constexpr auto total_bench_iterations = 3;

  double kernel_time_mad_sp = benchmark<total_bench_iterations>([&]() {
    const float seed_f = 1.0f;
    return launch_timed_kernel<float>(d_buffer, seed_f, compute_grid_size, workgroupsize,
                                      current_compute_iterations, (int)elements_per_wi,
                                      (int)fusion_degree, block_strided, use_os_timer);
  });

  double kernel_time_mad_dp = benchmark<total_bench_iterations>([&]() {
    if (!enable_dp) return 0.0;
    const double seed_d = 1.0;
    return launch_timed_kernel<double>(d_buffer, seed_d, compute_grid_size, workgroupsize,
                                       current_compute_iterations, (int)elements_per_wi,
                                       (int)fusion_degree, block_strided, use_os_timer);
  });

  double kernel_time_mad_hp = benchmark<total_bench_iterations>([&]() {
    if (!enable_hp) return 0.0;
    const __half2 seed_h = __float2half2_rn(1.0f);
    return launch_timed_kernel<__half2>(d_buffer, seed_h, compute_grid_size, workgroupsize,
                                        current_compute_iterations, (int)elements_per_wi,
                                        (int)fusion_degree, block_strided, use_os_timer);
  });

  double kernel_time_mad_int = benchmark<total_bench_iterations>([&]() {
    const int seed_i = 1;
    return launch_timed_kernel<int>(d_buffer, seed_i, compute_grid_size, workgroupsize,
                                    current_compute_iterations, (int)elements_per_wi,
                                    (int)fusion_degree, block_strided, use_os_timer);
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) /
          ((double)memoryoperations * sizeof(__half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp *
          1000. / (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
  const bool block_strided = false;
  const bool host_allocated = false;
  const bool use_os_timer = false;
  const size_t workgroupsize = 256;
  const unsigned int elements_per_wi = 8;
  const unsigned int fusion_degree = 4;

  const char* benchtype = block_strided ? "Workgroup" : "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation = host_allocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n", use_os_timer ? "OS based" : "CUDA event based");

  cudaDeviceProp props = GetDeviceProperties();
  bool enable_dp = (props.major > 1 || (props.major == 1 && props.minor >= 3));
  if (!enable_dp) {
    printf("Warning:                Double precision computations are not supported\n");
  }
  bool enable_hp = IsFP16Supported();
  if (!enable_hp) {
    printf("Warning:                Half precision computations are not supported\n");
  }

  void* d_buffer = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&d_buffer, (size_t)size * sizeof(double)));

  CUDA_SAFE_CALL(cudaMemset(d_buffer, 0, (size_t)size * sizeof(int)));

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  runbench_warmup(d_buffer, size, workgroupsize, block_strided);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  printf(
      "----------------------------------------------------------------------------- CSV data "
      "-----------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    runbench(compute_iterations, i, d_buffer, size, workgroupsize, elements_per_wi,
             fusion_degree, block_strided, use_os_timer, enable_dp, enable_hp);
  }

  printf(
      "--------------------------------------------------------------------------------------------------------"
      "----------------------------------------"
      "--------------------\n");

  CUDA_SAFE_CALL(cudaMemcpy(c, d_buffer, (size_t)size * sizeof(double), cudaMemcpyDeviceToHost));
  CUDA_SAFE_CALL(cudaFree(d_buffer));
}
